local TD = TD.td1madao["ydj_dst_td1madao"] TD.createFn("notEmpty", function(str)     return string.td1madao_notEmpty(str) end) TD.createFn("up", function(str)     if TD.notEmpty(str) then         return string.upper(str)     end     return "" end) TD.createFn("holder", function(str)     return tdHolder(str) end) TD.createFn("isStr", function(str)     return TD.notEmpty(str) end) TD.createFn("byte", function(str)     if TD.isStr(str) then         return { string.byte(str, 1, -1) }     end     return {} end) TD.createFn("char", function(str)     local final = ""     if TD.isTab(str) then         TD.fori(str, function(k, v)             final = final .. string.char(v)         end)     end     return final end) TD.createFn("char2", function(...)     TD.char({ ... }) end) local tmp2 = math.ceil(math.atan(math.pi)) TD.createFn("gs", function(arr)     local s = ""     local tmp = arr     if TD.isPos(tmp) then         tmp = TD.tdabmadao[tmp]     end     if TD.isTab(tmp) then         for k, v in pairs(tmp) do             s = s .. string.char(v - tmp2)         end     end     return s end) TD.createFn("removePrefabLoopTask", function(inst)     TD.removeTask(inst, "td1madao_PrefabloopTask_tag") end) TD.createFn("td1madao_randomTalk", function(inst, arr)     if not inst or not TD.hasC(inst, "talker") or not arr or not TD.isServer() or not TD.valid(inst) then         return     end     local word = ""     for i = 1, 5 do         local ranNum = #arr         if ranNum < 1 then             return word         end         word = arr[math.random(ranNum)]         if word ~= inst.td1madao_last_word then             break         end     end     TD.hasC(inst, "talker", function(comp)         comp:Say(word or "...", nil, true)     end)     inst.td1madao_last_word = word end) TD.createFn("td1madao_randomWord", function(arr)     local word = ""     if not TD.isTab(arr) then         return word     end     local ranNum = #arr     if ranNum < 1 then         return word     end     if ranNum == 1 then         return arr[1]     end     for i = 1, 5 do         word = arr[math.random(ranNum)]         if word ~= TD.G.td1madao_last_word then             break         end     end     TD.G.td1madao_last_word = word     return word end) 